import { useState } from 'react';
import { Card, Stack, Row, Text, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

const getWeatherEmoji = (condition: string): string => {
  const lowerCondition = condition.toLowerCase();
  if (lowerCondition.includes('sunny') || lowerCondition.includes('clear')) return '☀️';
  if (lowerCondition.includes('cloud')) return '☁️';
  if (lowerCondition.includes('rain')) return '🌧️';
  if (lowerCondition.includes('snow')) return '❄️';
  if (lowerCondition.includes('wind')) return '💨';
  if (lowerCondition.includes('storm') || lowerCondition.includes('thunder')) return '⛈️';
  if (lowerCondition.includes('fog') || lowerCondition.includes('mist')) return '🌫️';
  return '🌤️';
};

export default function GeneratedComponent({
  city = 'New York',
  temperature = 72,
  condition = 'Sunny',
  humidity = 65,
  windSpeed = 12,
  unit = '°F',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 75, low: 62 },
    { day: 'Tue', icon: '☁️', high: 70, low: 58 },
    { day: 'Wed', icon: '🌧️', high: 65, low: 55 },
    { day: 'Thu', icon: '☁️', high: 68, low: 57 },
    { day: 'Fri', icon: '☀️', high: 76, low: 61 },
  ],
}: Props) {
  const currentEmoji = getWeatherEmoji(condition);

  const getDayLabel = (day: string | undefined, index: number): string => {
    if (day) return day;
    const dayNum = index + 1;
    return 'Day ' + dayNum;
  };

  return (
    <Card padding={24} shadow="md">
      <Stack direction="vertical" gap={24}>
        {/* Header with city name */}
        <Stack direction="vertical" gap={8}>
          <Text variant="h2" color="var(--ggui-color-onSurface, #18181b)">
            {city}
          </Text>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Current Weather
          </Text>
        </Stack>

        {/* Current Weather Section */}
        <Stack direction="vertical" gap={16}>
          {/* Temperature and Condition */}
          <Row align="center" gap={16}>
            <Box>
              <Text
                style={{
                  fontSize: '64px',
                  fontWeight: 'bold',
                  lineHeight: '1',
                  color: 'var(--ggui-color-primary-600, #0284c7)',
                }}
              >
                {temperature}
              </Text>
            </Box>
            <Stack direction="vertical" gap={4} align="start">
              <Text
                style={{
                  fontSize: '48px',
                  lineHeight: '1',
                }}
              >
                {currentEmoji}
              </Text>
              <Text
                variant="body"
                color="var(--ggui-color-onSurface, #18181b)"
                weight="semibold"
              >
                {condition}
              </Text>
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                {unit}
              </Text>
            </Stack>
          </Row>

          {/* Humidity and Wind Speed */}
          <Row gap={16} justify="start">
            <Box
              padding={12}
              borderRadius="var(--ggui-shape-radius-md, 8px)"
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
              style={{ flex: 1 }}
            >
              <Stack direction="vertical" gap={4} align="start">
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  weight="medium"
                >
                  Humidity
                </Text>
                <Text
                  variant="body"
                  color="var(--ggui-color-onSurface, #18181b)"
                  weight="semibold"
                >
                  {humidity}%
                </Text>
              </Stack>
            </Box>

            <Box
              padding={12}
              borderRadius="var(--ggui-shape-radius-md, 8px)"
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
              style={{ flex: 1 }}
            >
              <Stack direction="vertical" gap={4} align="start">
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  weight="medium"
                >
                  Wind Speed
                </Text>
                <Text
                  variant="body"
                  color="var(--ggui-color-onSurface, #18181b)"
                  weight="semibold"
                >
                  {windSpeed} mph
                </Text>
              </Stack>
            </Box>
          </Row>
        </Stack>

        {/* Divider */}
        <Box
          style={{
            height: '1px',
            background: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        />

        {/* 5-Day Forecast */}
        <Stack direction="vertical" gap={8}>
          <Text
            variant="label"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
            weight="semibold"
          >
            5-Day Forecast
          </Text>

          <Row gap={8} justify="between" wrap>
            {forecast.map((day, idx) => (
              <Box
                key={idx}
                padding={12}
                borderRadius="var(--ggui-shape-radius-md, 8px)"
                background="var(--ggui-color-primary-50, #f0f9ff)"
                style={{
                  flex: '1 1 auto',
                  minWidth: '80px',
                  border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                }}
              >
                <Stack direction="vertical" gap={6} align="center">
                  <Text
                    variant="caption"
                    color="var(--ggui-color-primary-700, #0369a1)"
                    weight="semibold"
                  >
                    {getDayLabel(day.day, idx)}
                  </Text>
                  <Text style={{ fontSize: '24px', lineHeight: '1' }}>
                    {day.icon || '🌤️'}
                  </Text>
                  <Stack direction="horizontal" gap={4} justify="center">
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurface, #18181b)"
                      weight="semibold"
                    >
                      {day.high || '—'}°
                    </Text>
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    >
                      {day.low || '—'}°
                    </Text>
                  </Stack>
                </Stack>
              </Box>
            ))}
          </Row>
        </Stack>
      </Stack>
    </Card>
  );
}
